// // This module implements a 4-bit shift register that shifts its contents to the right by one position on each rising edge of the clock signal (clk) when the enable signal (en) is high. If the reset signal (rst_n) is low, the shift register should reset to 0. The input signal (din) is shifted into the most significant bit.
module shift_register(
    input wire clk,
    input wire rst_n,
    input wire en,
    input wire din,
    output reg [3:0] q
);

always @(posedge clk or negedge rst_n) begin
    if (!rst_n)
        q <= 4'd0;
    else if (en)
        q <= {q[2:0], din};
end

endmodule
